fn explicit_binding_is_admissible_for_status(
    binding: &crate::state_store::RunGraphContinuationBinding,
    status: &crate::state_store::RunGraphStatus,
) -> bool {
    if binding.run_id != status.run_id {
        return false;
    }
    if status.status != "completed" {
        return true;
    }

    matches!(
        binding
            .active_bounded_unit
            .get("kind")
            .and_then(serde_json::Value::as_str),
        Some("downstream_dispatch_target") | Some("task_graph_task")
    )
}

pub(crate) fn build_continuation_binding_summary(
    explicit_binding: Option<&crate::state_store::RunGraphContinuationBinding>,
    latest_run_graph_status: Option<&crate::state_store::RunGraphStatus>,
    latest_run_graph_recovery: Option<&crate::state_store::RunGraphRecoverySummary>,
    latest_run_graph_dispatch_receipt: Option<&crate::state_store::RunGraphDispatchReceiptSummary>,
    evidence_ambiguous: bool,
) -> serde_json::Value {
    if evidence_ambiguous {
        return serde_json::json!({
            "status": "ambiguous",
            "continuation_allowed": false,
            "active_bounded_unit": serde_json::Value::Null,
            "binding_source": serde_json::Value::Null,
            "why_this_unit": serde_json::Value::Null,
            "primary_path": "diagnosis_path",
            "sequential_vs_parallel_posture": "unknown_until_explicit_binding",
            "ambiguity_reason": "runtime_evidence_ambiguous",
            "next_actions": [
                "Do not continue by heuristic while run-graph continuation evidence is ambiguous.",
                "Refresh continuation evidence with `vida taskflow consume continue --json` and recheck `vida status --json` before selecting the next bounded step."
            ]
        });
    }

    let sequential_vs_parallel_posture = if latest_run_graph_recovery
        .is_some_and(|recovery| recovery.delegation_gate.delegated_cycle_open)
    {
        "sequential_only_open_cycle"
    } else {
        "sequential_only"
    };

    if let Some(status) = latest_run_graph_status {
        if let Some(binding) = explicit_binding {
            if explicit_binding_is_admissible_for_status(binding, status) {
                return serde_json::json!({
                    "status": binding.status,
                    "continuation_allowed": binding.status == "bound",
                    "active_bounded_unit": binding.active_bounded_unit,
                    "binding_source": binding.binding_source,
                    "why_this_unit": binding.why_this_unit,
                    "primary_path": binding.primary_path,
                    "sequential_vs_parallel_posture": binding.sequential_vs_parallel_posture,
                    "ambiguity_reason": serde_json::Value::Null,
                    "next_actions": []
                });
            }
        }

        if status.status != "completed" {
            return serde_json::json!({
                "status": "bound",
                "continuation_allowed": true,
                "active_bounded_unit": {
                    "kind": "run_graph_task",
                    "task_id": status.task_id,
                    "run_id": status.run_id,
                    "active_node": status.active_node,
                },
                "binding_source": "latest_run_graph_status",
                "why_this_unit": format!(
                    "Latest runtime state is still active for task `{}` at node `{}`.",
                    status.task_id, status.active_node
                ),
                "primary_path": "normal_delivery_path",
                "sequential_vs_parallel_posture": sequential_vs_parallel_posture,
                "ambiguity_reason": serde_json::Value::Null,
                "next_actions": []
            });
        }

        if let Some(receipt) = latest_run_graph_dispatch_receipt {
            let downstream_target = receipt
                .downstream_dispatch_target
                .as_deref()
                .filter(|value| !value.trim().is_empty());
            let downstream_status_ready = matches!(
                receipt.downstream_dispatch_status.as_deref(),
                Some("packet_ready") | Some("executed")
            );
            if receipt.downstream_dispatch_ready && downstream_status_ready {
                if let Some(dispatch_target) = downstream_target {
                    return serde_json::json!({
                        "status": "bound",
                        "continuation_allowed": true,
                        "active_bounded_unit": {
                            "kind": "downstream_dispatch_target",
                            "task_id": status.task_id,
                            "run_id": status.run_id,
                            "dispatch_target": dispatch_target,
                        },
                        "binding_source": "latest_run_graph_dispatch_receipt",
                        "why_this_unit": format!(
                            "Latest dispatch receipt explicitly names downstream target `{}` as the next lawful bounded unit.",
                            dispatch_target
                        ),
                        "primary_path": "normal_delivery_path",
                        "sequential_vs_parallel_posture": "sequential_only_downstream_bound",
                        "ambiguity_reason": serde_json::Value::Null,
                        "next_actions": []
                    });
                }
            }
        }

        return serde_json::json!({
            "status": "ambiguous",
            "continuation_allowed": false,
            "active_bounded_unit": serde_json::Value::Null,
            "binding_source": serde_json::Value::Null,
            "why_this_unit": serde_json::Value::Null,
            "primary_path": "diagnosis_path",
            "sequential_vs_parallel_posture": "unknown_until_explicit_binding",
            "ambiguity_reason": "completed_without_explicit_next_bounded_unit",
            "next_actions": [
                "Do not continue by selecting the next ready task heuristically after a completed bounded slice.",
                "Either cite the explicit next bounded unit from the user, bind it with `vida taskflow continuation bind <run-id> --task-id <task-id> --json`, or refresh runtime evidence with `vida taskflow consume continue --json` before further implementation."
            ]
        });
    }

    let mut entries = Vec::with_capacity(rows.len());
    for row in rows {
        let entry = row.as_str()?;
        let trimmed = entry.trim();
        if trimmed.is_empty() || trimmed != entry {
            return None;
        }
        entries.push(trimmed.to_string());
    }
    Some(entries)
}

fn resume_packet_ready_blocker_parity_error(
    downstream_dispatch_status: Option<&str>,
    downstream_dispatch_blockers: &[String],
) -> Option<String> {
    if downstream_dispatch_status == Some("packet_ready")
        && !downstream_dispatch_blockers.is_empty()
    {
        return Some(
            "Persisted downstream dispatch packet has packet_ready status but also blocker evidence"
                .to_string(),
        );
    }
    None
}

fn should_refresh_resumed_downstream_preview(
    receipt: &crate::state_store::RunGraphDispatchReceipt,
) -> bool {
    receipt.dispatch_status == "executed"
        && (!receipt.downstream_dispatch_ready || !receipt.downstream_dispatch_blockers.is_empty())
}

fn prepare_explicit_resume_retry_artifact(
    project_root: Option<&std::path::Path>,
    role_selection: &super::RuntimeConsumptionLaneSelection,
    dispatch_receipt: &mut crate::state_store::RunGraphDispatchReceipt,
) -> bool {
    if dispatch_receipt_retry_eligible(dispatch_receipt) {
        if let Some(fallback_backend) =
            retry_backend_for_dispatch_receipt(role_selection, dispatch_receipt)
        {
            dispatch_receipt.selected_backend = Some(fallback_backend);
        }
        dispatch_receipt.dispatch_status = "packet_ready".to_string();
        dispatch_receipt.lane_status = super::LaneStatus::PacketReady.as_str().to_string();
        dispatch_receipt.blocker_code = None;
        return true;
    }

    let Some(project_root) = project_root else {
        return false;
    };
    if dispatch_receipt_internal_retry_eligible(project_root, role_selection, dispatch_receipt) {
        dispatch_receipt.dispatch_status = "packet_ready".to_string();
        dispatch_receipt.lane_status = super::LaneStatus::PacketReady.as_str().to_string();
        dispatch_receipt.blocker_code = None;
        return true;
    }
    if let Some(primary_backend) =
        primary_backend_for_dispatch_receipt(project_root, role_selection, dispatch_receipt)
    {
        dispatch_receipt.selected_backend = Some(primary_backend);
        dispatch_receipt.dispatch_status = "packet_ready".to_string();
        dispatch_receipt.lane_status = super::LaneStatus::PacketReady.as_str().to_string();
        dispatch_receipt.blocker_code = None;
        return true;
    }
    if let Some(fallback_backend) = super::fallback_backend_for_blocked_primary_dispatch_receipt(
        project_root,
        role_selection,
        dispatch_receipt,
    ) {
        dispatch_receipt.selected_backend = Some(fallback_backend);
        dispatch_receipt.dispatch_status = "packet_ready".to_string();
        dispatch_receipt.lane_status = super::LaneStatus::PacketReady.as_str().to_string();
        dispatch_receipt.blocker_code = None;
        return true;
    }
    false
}

type TaskflowConsumeContinueArgs = (bool, Option<String>, Option<String>, Option<String>);

pub(crate) fn parse_taskflow_consume_continue_args(
    args: &[String],
) -> Result<TaskflowConsumeContinueArgs, String> {
    let mut as_json = false;
    let mut run_id = None;
    let mut dispatch_packet_path = None;
    let mut downstream_packet_path = None;
    let mut index = 2usize;
    while index < args.len() {
        match args[index].as_str() {
            "--json" => {
                as_json = true;
                index += 1;
            }
            "--run-id" => {
                let Some(value) = args.get(index + 1) else {
                    return Err("Usage: vida taskflow consume continue [--run-id <run_id>] [--dispatch-packet <path> | --downstream-packet <path>] [--json]".to_string());
                };
                run_id = Some(value.clone());
                index += 2;
            }
            "--dispatch-packet" => {
                let Some(value) = args.get(index + 1) else {
                    return Err("Usage: vida taskflow consume continue [--run-id <run_id>] [--dispatch-packet <path> | --downstream-packet <path>] [--json]".to_string());
                };
                dispatch_packet_path = Some(value.clone());
                index += 2;
            }
            "--downstream-packet" => {
                let Some(value) = args.get(index + 1) else {
                    return Err("Usage: vida taskflow consume continue [--run-id <run_id>] [--dispatch-packet <path> | --downstream-packet <path>] [--json]".to_string());
                };
                downstream_packet_path = Some(value.clone());
                index += 2;
            }
            other => {
                return Err(format!(
                    "Unsupported argument `{other}`. Usage: vida taskflow consume continue [--run-id <run_id>] [--dispatch-packet <path> | --downstream-packet <path>] [--json]"
                ));
            }
        }
    }
    if dispatch_packet_path.is_some() && downstream_packet_path.is_some() {
        return Err(
            "Use only one packet source: --dispatch-packet <path> or --downstream-packet <path>"
                .to_string(),
        );
    }
    Ok((
        as_json,
        run_id,
        dispatch_packet_path,
        downstream_packet_path,
    ))
}

pub(crate) fn parse_taskflow_consume_advance_args(
    args: &[String],
) -> Result<(bool, Option<String>, usize), String> {
    let mut as_json = false;
    let mut run_id = None;
    let mut max_rounds = 8usize;
    let mut index = 2usize;
    while index < args.len() {
        match args[index].as_str() {
            "--json" => {
                as_json = true;
                index += 1;
            }
            "--run-id" => {
                let Some(value) = args.get(index + 1) else {
                    return Err(
                        "Usage: vida taskflow consume advance [--run-id <run_id>] [--max-rounds <n>] [--json]"
                            .to_string(),
                    );
                };
                run_id = Some(value.clone());
                index += 2;
            }
            "--max-rounds" => {
                let Some(value) = args.get(index + 1) else {
                    return Err(
                        "Usage: vida taskflow consume advance [--run-id <run_id>] [--max-rounds <n>] [--json]"
                            .to_string(),
                    );
                };
                max_rounds = value
                    .parse::<usize>()
                    .map_err(|_| "Expected a positive integer for --max-rounds".to_string())?;
                if max_rounds == 0 {
                    return Err("--max-rounds must be greater than zero".to_string());
                }
                index += 2;
            }
            other => {
                return Err(format!(
                    "Unsupported argument `{other}`. Usage: vida taskflow consume advance [--run-id <run_id>] [--max-rounds <n>] [--json]"
                ));
            }
        }
    }
    Ok((as_json, run_id, max_rounds))
}

pub(crate) async fn run_taskflow_consume_resume_command(
    state_dir: std::path::PathBuf,
    as_json: bool,
    requested_run_id: Option<String>,
    requested_dispatch_packet_path: Option<String>,
